shader.vertex:
attribute vec3 Position;
attribute vec4 Color;
attribute vec2 TexCoord;
attribute vec4 RenderData;
attribute float Scale;
attribute vec2 AnchorPos;
attribute vec2 Point1;
attribute vec2 Point2;
attribute vec2 Point3;
attribute vec2 Point4;
attribute vec2 Point5;
attribute vec2 Point6;
attribute vec2 Point7;
vec2 Pos = vec2(Position.xy);
varying vec4 Color0;
varying vec2 TexCoord0;
varying vec4 RenderDataOut;
varying float ScaleOut;
varying vec2 AnchorPosOut;
varying vec2 PosOut;
varying vec2 Point1Out;
varying vec2 Point2Out;
varying vec2 Point3Out;
varying vec2 Point4Out;
varying vec2 Point5Out;
varying vec2 Point6Out;
varying vec2 Point7Out;
uniform mat4 Transform;
void main(void)
{
    RenderDataOut = RenderData;
    ScaleOut = Scale;
    Color0 = Color;
    TexCoord0 = TexCoord;
    AnchorPosOut = AnchorPos;
    PosOut = Pos;
    Point1Out = Point1;
    Point2Out = Point2;
    Point3Out = Point3;
    Point4Out = Point4;
    Point5Out = Point5;
    Point6Out = Point6;
    Point7Out = Point7;
    gl_Position = Transform * vec4(Position.xyz, 1.0);
}

shader.fragment:
            varying lowp vec4 Color0;
            varying mediump vec2 TexCoord0;
            varying lowp vec4 RenderDataOut;
            varying lowp float ScaleOut;
            varying lowp vec2 AnchorPosOut;
            varying lowp vec2 PosOut;
            varying lowp vec2 Point1Out;
            varying lowp vec2 Point2Out;
            varying lowp vec2 Point3Out;
            varying lowp vec2 Point4Out;
            varying lowp vec2 Point5Out;
            varying lowp vec2 Point6Out;
            varying lowp vec2 Point7Out;
            uniform sampler2D Texture0;

            vec2 getPoint(int n)
            {
                if (n == 1) {return Point1Out;}
                if (n == 2) {return Point2Out;}
                if (n == 3) {return Point3Out;}
                if (n == 4) {return Point4Out;}
                if (n == 5) {return Point5Out;}
                if (n == 6) {return Point6Out;}
                if (n == 7) {return Point7Out;}
                return vec2(0, 0);
            }

            vec2 getLastPoint(int n, int max)
            {
                n = n - 1;
                if (n < 1) {
                    n = max + n;
                }

                if (n == 1) {return Point1Out;}
                if (n == 2) {return Point2Out;}
                if (n == 3) {return Point3Out;}
                if (n == 4) {return Point4Out;}
                if (n == 5) {return Point5Out;}
                if (n == 6) {return Point6Out;}
                if (n == 7) {return Point7Out;}
                return vec2(0, 0);
            }

            vec2 getNextPoint(int n, int max)
            {
                n = n + 1;
                if (n > max) {
                    n = n - max;
                }

                if (n == 1) {return Point1Out;}
                if (n == 2) {return Point2Out;}
                if (n == 3) {return Point3Out;}
                if (n == 4) {return Point4Out;}
                if (n == 5) {return Point5Out;}
                if (n == 6) {return Point6Out;}
                if (n == 7) {return Point7Out;}
                return vec2(0, 0);
            }

            float getAngleDegrees(vec2 v) {
                return degrees(atan(v.y, v.x));
            }

            vec2 rotate(vec2 v, float a) {
                a = radians(a);
	            float s = sin(a);
	            float c = cos(a);
	            mat2 m = mat2(c, s, -s, c);
	            return m * v;
            }

            void main(void)
            {
                vec4 Color = Color0 * texture2D(Texture0, TexCoord0);

                int sides = 0;
                if (Point1Out.x != 0 && Point1Out.y != 0) {sides++;}
                if (Point2Out.x != 0 && Point2Out.y != 0) {sides++;}
                if (Point3Out.x != 0 && Point3Out.y != 0) {sides++;}
                if (Point4Out.x != 0 && Point4Out.y != 0) {sides++;}
                if (Point5Out.x != 0 && Point5Out.y != 0) {sides++;}
                if (Point6Out.x != 0 && Point6Out.y != 0) {sides++;}
                if (Point7Out.x != 0 && Point7Out.y != 0) {sides++;}

                if (sides >= 3) {
                    vec2 Anchor = AnchorPosOut;
                    vec2 pos = PosOut - Anchor;
                    bool isInside = true;
                    bool isInsideOutline = true;

                    for (int i = 1; i <= sides; i++) {
                        vec2 sidePos = getPoint(i);
                        vec2 lastPos = getLastPoint(i, sides);
                        vec2 nextPos = getNextPoint(i, sides);
                        float anchorToSidePos = getAngleDegrees(sidePos);

                        float lastPosDegrees = getAngleDegrees(rotate(lastPos - sidePos, -anchorToSidePos));
                        float nextPosDegrees = getAngleDegrees(rotate(nextPos - sidePos, -anchorToSidePos));
                        float toPointDegrees = getAngleDegrees(rotate(pos - sidePos, -anchorToSidePos));

                        if ((toPointDegrees >= nextPosDegrees == false) && (toPointDegrees <= lastPosDegrees == false)) {
                            isInside = false;
                            break;
                        }
                    }

                    for (int i = 1; i <= sides; i++) {
                        vec2 sidePos = getPoint(i) * (1.025 + i/sides);
                        vec2 lastPos = getLastPoint(i, sides) * (1.05 + sides/(i + 10));
                        vec2 nextPos = getNextPoint(i, sides) * (1.05 + (sides)/((i + 3) * i));
                        float anchorToSidePos = getAngleDegrees(sidePos);

                        float lastPosDegrees = getAngleDegrees(rotate(lastPos - sidePos, -anchorToSidePos));
                        float nextPosDegrees = getAngleDegrees(rotate(nextPos - sidePos, -anchorToSidePos));
                        float toPointDegrees = getAngleDegrees(rotate(pos - sidePos, -anchorToSidePos));

                        if ((toPointDegrees >= nextPosDegrees == false) && (toPointDegrees <= lastPosDegrees == false)) {
                            isInsideOutline = false;
                            break;
                        }
                    }

                    if (isInside == true) {
                        vec4 ColorHelper = Color0 * texture2D(Texture0, TexCoord0);

                        ColorHelper.r *= 0.25 + ColorHelper.r;
                        ColorHelper.g *= 0.3 + ColorHelper.g;
                        ColorHelper.b *= 0.3 + ColorHelper.b;
                        ColorHelper.r += 0.22;
                        ColorHelper.g += 0.215;
                        ColorHelper.b += 0.215;

                        float similarityTo1stColor = abs(-ColorHelper.r -ColorHelper.g -ColorHelper.b);
                        float similarityTo2ndColor = abs(0.674 - ColorHelper.r + 0.549 - ColorHelper.g + 0.549 - ColorHelper.b);
                        float similarityTo3rdColor = abs(0.894 - ColorHelper.r + 0.871 - ColorHelper.g + 0.839 - ColorHelper.b);

                        if (similarityTo1stColor < similarityTo2ndColor) {
                            Color.r += 0 - Color.r;
                            Color.g += 0 - Color.g;
                            Color.b += 0 - Color.b;
                        } else if (similarityTo2ndColor < similarityTo1stColor && similarityTo2ndColor < similarityTo3rdColor) {
                            Color.r += 0.674 - Color.r;
                            Color.g += 0.549 - Color.g;
                            Color.b += 0.549 - Color.b;
                        } else {
                            Color.r += 0.894 - Color.r;
                            Color.g += 0.871 - Color.g;
                            Color.b += 0.839 - Color.b;
                        }
                    } else if (isInsideOutline == true) {
                        Color.r = 0;
                        Color.g = 0;
                        Color.b = 0;
                    }
                }

                gl_FragColor = Color;
            }

shader.vertex:
attribute vec3 Position;
attribute vec4 Color;
attribute vec2 TexCoord;
attribute vec2 CenterPos;
attribute float Radius;
attribute float Time;
attribute vec2 CameraPos;
attribute float Active;
attribute float Intensity;
attribute float MinIntensity;
attribute float FogColorR;
attribute float FogColorG;
attribute float FogColorB;

vec2 Pos = vec2(Position.xy);

varying vec4 Color0;
varying vec2 TexCoord0;

varying vec2 PosOut;
varying vec2 CenterPosOut;
varying float ActiveOut;
varying float RadiusOut;
varying float TimeOut;
varying vec2 CameraPosOut;
varying float IntensityOut;
varying float MinIntensityOut;
varying float FogColorROut;
varying float FogColorGOut;
varying float FogColorBOut;

uniform mat4 Transform;

void main(void) {
    Color0 = Color;
    TexCoord0 = TexCoord;

    PosOut = Pos;
    CenterPosOut = CenterPos;
    RadiusOut = Radius;
    TimeOut = Time;
    CameraPosOut = CameraPos;
    ActiveOut = Active;
    IntensityOut = Intensity;
    MinIntensityOut = MinIntensity;
    FogColorROut = FogColorR;
    FogColorGOut = FogColorG;
    FogColorBOut = FogColorB;

    gl_Position = Transform * vec4(Position.xyz, 1.0);
}

shader.fragment:
varying lowp vec4 Color0;
varying mediump vec2 TexCoord0;
uniform sampler2D Texture0;

varying vec2 PosOut;
varying vec2 CenterPosOut;
varying float RadiusOut;
varying float TimeOut;
varying vec2 CameraPosOut;
varying float ActiveOut;
varying float IntensityOut;
varying float MinIntensityOut;
varying float FogColorROut;
varying float FogColorGOut;
varying float FogColorBOut;

// Hash function for pseudo-random values
float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

// Smooth value noise - creates blobby shapes
float vnoise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    // Smooth interpolation curve
    vec2 u = f * f * (3.0 - 2.0 * f);

    // Sample 4 corners and interpolate
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));

    return mix(mix(a, b, u.x), mix(c, d, u.x), u.y);
}

// Layered noise for more organic blobs
float fbm(vec2 p) {
    float value = 0.0;
    float amplitude = 0.5;
    for (int i = 0; i < 5; i++) {
        value += amplitude * vnoise(p);
        p *= 2.0;
        amplitude *= 0.5;
    }
    return value;
}

void main(void) {
    vec4 Color = Color0 * texture2D(Texture0, TexCoord0);


    if (ActiveOut != 0) {

    // Layer stretch (x, y) - lower = larger/more stretched
    vec2 layer1Scale = vec2(0.015, 0.03);
    vec2 layer2Scale = vec2(0.025, 0.045);
    vec2 layer3Scale = vec2(0.04, 0.065);

    // Layer colors
    vec3 baseFogColor = vec3(0.75, 0.75, 0.8);
    vec3 layer1Color = vec3(0.45, 0.45, 0.52);
    vec3 layer2Color = vec3(0.35, 0.38, 0.46);
    vec3 layer3Color = vec3(0.85, 0.85, 0.9);

    float dist = distance(PosOut, CenterPosOut);

    // Original fade curve: 0 inside radius, ramps up outside
    float mult = RadiusOut / max(dist, 0.001);
    float x1 = 0.1 * min((dist - RadiusOut) / RadiusOut, 1.0);
    float fogFactor = clamp(1.0 - mult + x1, MinIntensityOut, 1.0);

    // World-space position for camera-dependent fog
    vec2 worldPos = PosOut + CameraPosOut;

    // Layer 1: large slow-moving blobs
    vec2 coord1 = worldPos * layer1Scale + vec2(TimeOut * 0.16, cos(TimeOut * 0.03));
    float layer1 = fbm(coord1);

    // Layer 2: medium blobs, different direction
    vec2 coord2 = worldPos * layer2Scale + vec2(-TimeOut * 0.24, sin(TimeOut * 0.05));
    float layer2 = fbm(coord2 + 50.0);

    // Layer 3: smaller, faster wisps
    vec2 coord3 = worldPos * layer3Scale + vec2(TimeOut * 0.36, -TimeOut * 0.08);
    float layer3 = fbm(coord3 + 120.0);

    // Each layer contributes a different shade
    float d1 = smoothstep(0.35, 0.65, layer1);
    float d2 = smoothstep(0.4, 0.7, layer2);
    float d3 = smoothstep(0.4, 0.65, layer3);

    // Vary color per layer for depth
    vec3 fogColor1 = mix(baseFogColor, layer1Color, d1 * 0.5);
    vec3 fogColor2 = mix(baseFogColor, layer2Color, d2 * 0.4);
    vec3 fogColor3 = mix(baseFogColor, layer3Color, d3 * 0.35);

    // Combine layers
    vec3 finalFogColor = (fogColor1 * 0.4 + fogColor2 * 0.35 + fogColor3 * 0.25) * vec3(FogColorROut, FogColorGOut, FogColorBOut);



    float minIntensity = MinIntensityOut + IntensityOut/10;
    if (fogFactor < minIntensity) {
        fogFactor = minIntensity;
    }
    fogFactor = min(fogFactor + dist/1000, 1);
    fogFactor *= IntensityOut;

    // Blend scene with fog color using the original fade curve
    Color.rgb = mix(Color.rgb, finalFogColor, fogFactor);

    }


    gl_FragColor = Color;
}
